#!/usr/bin/env python3
import socket

hedef = "10.10.10.1"
for port in range(1, 1025):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(0.5)
    if s.connect_ex((hedef, port)) == 0:
        print(f"[+] Port {port} AÇIK")
    s.close()
